// Current «Власний Рахунок» mark — magenta/violet "6" loop
export const VR6Mark = ({ size = 24, color }) => (
  <svg width={size} height={size} viewBox="0 0 24 24" fill="none">
    <defs>
      <linearGradient id="vr6_g" x1="6" y1="4" x2="18" y2="20" gradientUnits="userSpaceOnUse">
        <stop stopColor="#FF2E92"/>
        <stop offset="1" stopColor="#A521E0"/>
      </linearGradient>
    </defs>
    <path d="M15.6 3.6c-4.2 2.9-7.6 6.6-8.1 10.6" stroke={color || 'url(#vr6_g)'} strokeWidth="4.4" strokeLinecap="round"/>
    <circle cx="12" cy="15.6" r="4.4" stroke={color || 'url(#vr6_g)'} strokeWidth="4.4"/>
  </svg>
);

// Service tile icon — gradient rounded square/circle with a glyph
