// Category tile icon: detailed 48px asset where available, else the glyph in a blue-100 circle
export const CategoryTileIcon = ({ kind }) => {
  const detailed = DetailedCategoryIcon({ kind });
  if (detailed) return detailed;
  return (
    <div style={{ width: 48, height: 48, borderRadius: 60, background: '#EEF2FC', padding: 8,
      display: 'grid', placeItems: 'center', boxSizing: 'border-box' }}>
      <CategoryIcon kind={kind} size={32}/>
    </div>
  );
};

