// promo bubble badges sitting on product images
export const PromoBubble = ({ kind }) => {
  if (kind === 'tsino') return (
    <div style={{ position: 'absolute', left: 0, top: 0, width: 34, height: 34, borderRadius: 34, background: '#FFCD00', display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center', lineHeight: .82, color: '#04000D', fontWeight: 900, boxShadow: 'var(--shadow-volume)' }}>
      <span style={{ fontSize: 8 }}>Ціно</span><span style={{ fontSize: 7 }}>тижики</span></div>);
  if (kind === 'klatsni') return (
    <div style={{ position: 'absolute', left: 0, top: 0, width: 32, height: 32, borderRadius: 32, background: '#0600E7', display: 'grid', placeItems: 'center', boxShadow: 'var(--shadow-volume)' }}>
      <svg width="15" height="15" viewBox="0 0 24 24" fill="#fff"><path d="M13 2 4 14h6l-1 8 9-12h-6l1-8z"/></svg></div>);
  return null;
};
